def select_next_node(current_node: int, depot: int, unvisited_nodes: np.ndarray,
                     rest_capacity: float, demands: np.ndarray,
                     distance_matrix: np.ndarray) -> int:
    if len(unvisited_nodes) == 0:
        return depot

    # Compute distances from current node to all unvisited nodes
    dists = distance_matrix[current_node][unvisited_nodes]
    # Compute distances from depot to all unvisited nodes
    depot_dists = distance_matrix[depot][unvisited_nodes]

    # If at depot or just starting a new route (small current distance from depot), use farthest-first seeding
    if current_node == depot or distance_matrix[depot][current_node] < 0.1 * np.max(distance_matrix[depot]):
        # Prefer farthest from depot, but if rest_capacity is small (almost full), switch to nearest
        if rest_capacity < 0.3 * np.max(demands[unvisited_nodes]) + 1e-9:
            best_idx = np.argmin(dists)
        else:
            best_idx = np.argmax(depot_dists)
    else:
        # Once away from depot, use nearest neighbor
        best_idx = np.argmin(dists)

    return int(unvisited_nodes[best_idx])

