def select_next_node(current_node: int, depot: int, unvisited_nodes: np.ndarray,
                     rest_capacity: float, demands: np.ndarray,
                     distance_matrix: np.ndarray) -> int:
    if len(unvisited_nodes) == 0:
        return depot

    # If at depot or early in route (few nodes visited), seed toward distant clusters
    if current_node == depot:
        farthest_idx = np.argmax(distance_matrix[depot][unvisited_nodes])
        return int(unvisited_nodes[farthest_idx])

    # Compute distance from current node and from depot
    dist_from_current = distance_matrix[current_node][unvisited_nodes]
    dist_from_depot = distance_matrix[depot][unvisited_nodes]

    # Determine if we are still near the depot (within lower half of max depot distance)
    max_depot_dist = np.max(distance_matrix[depot])
    if distance_matrix[depot][current_node] <= 0.5 * max_depot_dist:
        # Still near depot: prefer far nodes to seed route outward
        score = -dist_from_depot + 0.3 * dist_from_current
    else:
        # Away from depot: use nearest neighbor
        score = dist_from_current

    best_idx = np.argmin(score)
    return int(unvisited_nodes[best_idx])

